import { expect, test } from "bun:test";
import { LoadingScreenDataSchema } from "@scout-for-lol/data";
import {
  loadingScreenToImage,
  loadingScreenToSvg,
} from "#src/html/loading-screen/index.tsx";
import { getArenaTrackedParticipants } from "#src/html/loading-screen/arena-layout.tsx";

const currentDir = new URL(".", import.meta.url).pathname;

/**
 * Check if champion loading screen images have been downloaded.
 * These are generated by `bun run update-data-dragon` in packages/data.
 */
async function hasLoadingScreenAssets(): Promise<boolean> {
  const testImage = new URL(
    "../../../dataDragon/../../../packages/data/src/data-dragon/assets/img/champion-loading/Aatrox_0.jpg",
    import.meta.url,
  );
  const file = Bun.file(testImage);
  return file.exists();
}

test("Arena loading screen renders only tracked player champions", async () => {
  const assetsExist = await hasLoadingScreenAssets();
  if (!assetsExist) {
    console.warn(
      "Skipping Arena 3v3 loading-screen render test: champion loading images not found. Run 'bun run update-data-dragon' in packages/data first.",
    );
    return;
  }

  const raw = await Bun.file(`${currentDir}testdata/arena-3v3.json`).json();
  const data = LoadingScreenDataSchema.parse(raw);

  expect(data.participants).toHaveLength(18);
  if (data.layout !== "arena") {
    throw new Error(`Expected arena layout, received ${data.layout}`);
  }
  expect(getArenaTrackedParticipants(data)).toHaveLength(1);

  const svg = await loadingScreenToSvg(data);
  const png = await loadingScreenToImage(data);

  expect(svg.slice(0, 4)).toBe("<svg");
  expect(png.byteLength).toBeGreaterThan(1000);
});
